/* The queue frontend for catsoop-pyqueue.
 *
 * A dependency-free port of the original catsoop-queue frontend bundle
 * (www/js/queue.js + view.js + the Ractive templates), layered on the
 * WebSocket client in client.js (loaded automatically if not already
 * present).  No jQuery, Ractive, moment, or Mousetrap.
 *
 * Usage is the same as the original: a CAT-SOOP page defines
 *
 *   catsoop.plugins.queue = {url_root, is_staff, container, view, room, auth}
 *
 * where `auth` is the signed credential string generated by the queue
 * plugin's post_load.py (an HMAC-signed cs_user_info payload; the
 * queue server verifies it with the queue user's API token).  For
 * older CAT-SOOP versions that still define catsoop.api_token, that is
 * used as a fallback.  `url_root` may be a path or an absolute URL.
 * Including this script then creates a global `queue` object with the
 * same API surface the plugin code used: queue.get / set / observe /
 * add / remove / login / ...
 *
 * Views: 'staff_view' (table + claim view), 'student_static',
 * 'student_popup'.  Optional overrides in window.queue_www_params:
 * {SHOW_STAFF_LIST, get_photo_url, get_audio_url}.
 */

(function () {
'use strict';

const ENTRY_TYPES = {
    'help': {
        buttons: {
            'claim': {text: 'claim', shortcuts: []},
            'disclaim': {text: 'disclaim', shortcuts: ['d']},
            'remove': {text: 'remove', shortcuts: ['r']},
        },
    },
    'checkoff': {
        buttons: {
            'claim': {text: 'claim', shortcuts: []},
            'disclaim': {text: 'disclaim', shortcuts: ['d']},
            'remove': {text: 'remove', shortcuts: ['r']},
            'group_checkoff': {text: 'group checkoff', shortcuts: ['g']},
            'single_checkoff': {text: 'single checkoff', shortcuts: ['s']},
        },
    },
};

/// Small helpers

function path_join() {
    return Array.prototype.slice.call(arguments).join('/').replace(/\/+/g, '/');
}

// Join parts onto a url_root that may be a path ('/queue/') or an
// absolute URL ('http://localhost:3100') without mangling '://'.
function url_join(root) {
    const parts = Array.prototype.slice.call(arguments, 1)
        .map(p => String(p).replace(/^\/+|\/+$/g, ''));
    return (root || '').replace(/\/+$/, '') + '/' + parts.join('/');
}

// The WebSocket endpoint for a given url_root.
function ws_url(root) {
    root = root || '/';
    if (/^https?:\/\//.test(root)) {
        return url_join(root.replace(/^http/, 'ws'), 'ws');
    }
    const proto = window.location.protocol === 'https:' ? 'wss:' : 'ws:';
    return proto + '//' + window.location.host + path_join('/', root, '/ws');
}

function escapeHtml(value) {
    return String(value == null ? '' : value)
        .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

function page_basename(page) {
    return page ? String(page).split('/').slice(-1)[0] : '';
}

function otherMemberNames(group, primary) {
    return (group || [])
        .map(m => m.username !== primary ? ', ' + (m.real_name || m.username) : '')
        .join('');
}

function timeAgo(iso) {
    const seconds = Math.max(0, ((Date.now() - Date.parse(iso)) / 1000) | 0);
    if (seconds < 60) return seconds + 's';
    const minutes = (seconds / 60) | 0;
    if (minutes < 60) return minutes + 'm';
    return ((minutes / 60) | 0) + 'h ' + (minutes % 60) + 'm';
}

function claimTimer(iso) {
    const seconds = Math.max(0, ((Date.now() - Date.parse(iso)) / 1000) | 0);
    const secs = seconds % 60;
    return ((seconds / 60) | 0) + ':' + (secs < 10 ? '0' : '') + secs;
}

function queue_sort_order(x, y) {
    const a = [Boolean(x.data.claimant), x.date_added];
    const b = [Boolean(y.data.claimant), y.date_added];
    for (let i = 0; i < a.length; i++) {
        if (a[i] < b[i]) return -1;
        if (a[i] > b[i]) return +1;
    }
    return 0;
}

function modal(title, body, input, cancelable) {
    // Use CAT-SOOP's modal when present, else fall back to native dialogs.
    if (window.catsoop && catsoop.modal) {
        return Promise.resolve(catsoop.modal(title, body, input, cancelable));
    }
    if (input) return Promise.resolve({value: window.prompt(title + '\n' + body)});
    if (cancelable) return Promise.resolve(window.confirm(title + '\n' + body));
    window.alert(title + '\n' + body);
    return Promise.resolve(false);
}

function ensure_stylesheet(url_root) {
    // The CAT-SOOP plugin normally adds <link href=".../css/queue.css">
    // itself; add it here only if the page didn't.
    const already = Array.prototype.some.call(
        document.querySelectorAll('link[rel="stylesheet"]'),
        link => /\/queue\.css(\?|$)/.test(link.getAttribute('href') || ''));
    if (already) return;
    const link = document.createElement('link');
    link.rel = 'stylesheet';
    link.href = url_join(url_root || '/', 'css', 'queue.css');
    document.head.appendChild(link);
}

/// A tiny observable model (stands in for Ractive's get/set/observe)

class Model {
    constructor() {
        this._data = {};
        this._observers = {};
    }

    get(key) {
        return this._data[key];
    }

    set(key, value) {
        const old = this._data[key];
        this._data[key] = value;
        (this._observers[key] || []).forEach(fn => fn.call(this, value, old));
        return Promise.resolve();
    }

    toggle(key) {
        return this.set(key, !this.get(key));
    }

    observe(key, fn) {
        (this._observers[key] = this._observers[key] || []).push(fn);
        fn.call(this, this.get(key), undefined);
    }
}

/// The view: renders the queue into a container and handles UI events

class View extends Model {
    constructor(client, options) {
        super();
        this.client = client;
        this.options = options;
        this.container = document.querySelector(options.container || 'body');
        if (options.view === 'student_popup') {
            const div = document.createElement('div');
            this.container.appendChild(div);
            this.container = div;
        }

        ensure_stylesheet(options.url_root);

        this.set('entries', []);
        this.set('permissions', {});
        this.set('confirmed_staff', []);
        this.set('unconfirmed_staff', []);
        this.set('_visible', false);

        // Recompute derived values whenever the inputs change.
        ['entries', 'locked', 'disconnected', 'permissions', 'show_claimed',
         'confirmed_staff', 'unconfirmed_staff', '_visible',
         'notify_sound', 'notify_toast'].forEach(key => {
            this.observe(key, () => {
                this._recompute();
                this._schedule_render();
            });
        });

        this._wire_events();
        setInterval(() => this._tick(), 1000);
    }

    _recompute() {
        const entries = this.get('entries') || [];
        const username = this.client.username;
        this.set_silent('current_claim',
            entries.find(e => e.data.claimant === username));
        this.set_silent('my_entry',
            entries.find(e => e.username === username));
        this.set_silent('position',
            entries.filter(e => e.data.state === 'unclaimed')
                   .findIndex(e => e.username === username) + 1);
        this.set_silent('num_claimed',
            entries.filter(e => e.data.claimant).length);
        this.set_silent('num_unclaimed',
            entries.length - this.get('num_claimed'));
        this.set_silent('fraction_unclaimed',
            [this.get('num_unclaimed'), entries.length]);
        this.set_silent('first_unclaimed',
            entries.find(e => e.data.state === 'unclaimed') || null);
        this.set_silent('display_entries',
            entries.filter(e => this.get('show_claimed') || !e.data.claimant));
    }

    // set() that notifies observers but doesn't re-trigger recompute loops
    set_silent(key, value) {
        const old = this._data[key];
        this._data[key] = value;
        (this._observers[key] || []).forEach(fn => fn.call(this, value, old));
    }

    _schedule_render() {
        if (this._render_queued) return;
        this._render_queued = true;
        Promise.resolve().then(() => {
            this._render_queued = false;
            this.render();
        });
    }

    /// Rendering

    render() {
        // Preserve form input state across re-renders.
        const active = document.activeElement;
        const focus_id = active && this.container.contains(active) ? active.id : null;

        let html;
        if (this.options.view === 'staff_view') html = this._staff_view();
        else if (this.options.view === 'student_popup') html = this._student_popup();
        else html = this._student_static();
        this.container.innerHTML = html;

        if (focus_id) {
            const el = document.getElementById(focus_id);
            if (el) {
                el.focus();
                if (el.setSelectionRange && el.value != null) {
                    el.setSelectionRange(el.value.length, el.value.length);
                }
            }
        }
    }

    _banners() {
        let html = '';
        if (this.get('disconnected')) {
            html += '<div class="queue-disconnected"><strong>Disconnected!</strong> ' +
                'Your client has disconnected from the server. ' +
                'Please check your network connection.</div>';
        }
        if (this.get('locked')) {
            html += '<div class="queue-locked-banner"><strong>The queue is locked.</strong> ' +
                'It is not accepting new entries.</div>';
        }
        return html;
    }

    _staff_view() {
        let html = this._banners();
        if (this.options.SHOW_STAFF_LIST) html += this._staff_list();
        html += this.get('current_claim') ? this._claim() : this._table();
        return html;
    }

    _table() {
        const first = this.get('first_unclaimed');
        let html = '<div style="text-align:center">' +
            '<button class="queue-btn queue-btn-primary queue-btn-lg" data-claim-first' +
            (first ? '' : ' disabled') + '>Claim First Unclaimed (c)</button></div>';

        html += '<table class="queue-table"><thead><tr>' +
            '<th>#</th><th>Name</th><th>Assignment</th><th>Location</th>' +
            '<th>Staff</th><th>Timing</th><th>Actions</th></tr></thead><tbody>';

        (this.get('display_entries') || []).forEach((entry, i) => {
            const assignment = entry.data.assignment || {};
            const buttons = (entry.actions || []).map(action => {
                const spec = (ENTRY_TYPES[entry.type] || {buttons: {}}).buttons[action];
                return '<button class="queue-btn" data-act="' + escapeHtml(action) +
                    '" data-entry="' + escapeHtml(entry.username) + '">' +
                    escapeHtml(spec ? spec.text : action) + '</button>';
            }).join('');
            html += '<tr class="queue-row" data-type="' + escapeHtml(entry.type) +
                '" data-state="' + escapeHtml(entry.data.state) + '">' +
                '<td>' + (i + 1) + '</td>' +
                '<td>' + escapeHtml((entry.real_name || entry.username.slice(0, 10)) +
                                    otherMemberNames(entry.data.group, entry.username)) + '</td>' +
                '<td>' + escapeHtml(page_basename(assignment.page)) +
                    (assignment.display_name ? ': ' + escapeHtml(assignment.display_name) : '') +
                    (entry.data.state === 'claimed' ? ' (' + escapeHtml(entry.type) + ')' : '') + '</td>' +
                '<td>' + escapeHtml(entry.data.location) + '</td>' +
                '<td>' + escapeHtml(entry.data.state === 'claimed'
                                    ? entry.data.claimant_real_name : '') + '</td>' +
                '<td class="queue-time" data-since="' + escapeHtml(entry.last_modified) + '">' +
                    timeAgo(entry.last_modified) + '</td>' +
                '<td>' + buttons + '</td></tr>';
        });
        html += '</tbody></table>';

        html += '<p>' + this.get('num_claimed') + ' claimed. ' +
            this.get('num_unclaimed') + ' unclaimed.</p>';

        html += '<div class="queue-controls">';
        const permissions = this.get('permissions') || {};
        if (permissions.show_claimed) {
            html += '<button class="queue-btn" data-toggle-setting="show_claimed">' +
                (this.get('show_claimed') ? 'Hide' : 'Show') + ' Claimed</button>';
        }
        if (permissions.clear) {
            html += '<button class="queue-btn queue-btn-danger" data-clear>Clear Queue</button>';
        }
        if (permissions.lock) {
            html += this.get('locked')
                ? '<button class="queue-btn" data-unlock>Unlock Queue</button>'
                : '<button class="queue-btn" data-lock>Lock Queue</button>';
        }
        if (permissions.notifications) html += this._notify_buttons();
        html += '</div>';

        html += '<div style="padding-top:1em">' +
            '<a href="?queue_view=student">Switch to student view</a></div>';
        html += this._audio();
        return html;
    }

    _claim() {
        const claim = this.get('current_claim');
        const assignment = claim.data.assignment || {};
        const buttons = (claim.actions || []).map(action => {
            const spec = (ENTRY_TYPES[claim.type] || {buttons: {}}).buttons[action] || {};
            const shortcut = (spec.shortcuts || [])[0] || '';
            return '<button class="queue-btn queue-btn-lg action-button"' +
                ' data-act="' + escapeHtml(action) + '"' +
                ' data-entry="' + escapeHtml(claim.username) + '"' +
                ' data-shortcut="' + escapeHtml(shortcut) + '">' +
                escapeHtml(spec.text || action) +
                (shortcut ? ' (' + escapeHtml(shortcut) + ')' : '') + '</button>';
        }).join('');

        let html = '<div>' + buttons + '</div>';
        html += '<p class="queue-claim-time" data-claim-since="' +
            escapeHtml(claim.last_modified) + '">' +
            claimTimer(claim.last_modified) + '</p>';
        html += '<p><strong>' + escapeHtml(page_basename(assignment.page)) +
            (assignment.display_name ? ': ' + escapeHtml(assignment.display_name) : '') +
            '</strong></p>';
        if (claim.data.location) {
            html += '<p>Location: ' + escapeHtml(claim.data.location) + '</p>';
        }
        if (claim.data.meeting_url) {
            html += '<p><a href="' + escapeHtml(claim.data.meeting_url) +
                '">Meeting link</a></p>';
        }
        html += '<div>';
        (claim.data.group || []).forEach(member => {
            html += '<div class="queue-claim-student">';
            if (this.options.PHOTOS_ENABLED) {
                html += '<img src="' +
                    escapeHtml(this.options.get_photo_url(member.username)) + '">';
            }
            html += '<div><strong>' + escapeHtml(member.username) + '</strong></div>' +
                '<div>' + escapeHtml(member.real_name) + '</div></div>';
        });
        html += '</div>' + this._audio();
        return html;
    }

    _staff_list() {
        const confirmed = this.get('confirmed_staff') || [];
        const unconfirmed = this.get('unconfirmed_staff') || [];
        let html = '<div class="queue-staff-list"><div><strong>Staff on duty</strong><ul>';
        confirmed.forEach(username => {
            html += '<li>' + escapeHtml(username) +
                ' <a href="#" data-check-out="' + escapeHtml(username) + '">✕</a></li>';
        });
        html += '</ul>';
        if (confirmed.length) {
            html += '<button class="queue-btn queue-btn-danger" data-check-out-all>' +
                'Remove all staff</button>';
        }
        html += '</div><div><strong>Pending</strong><ul>';
        unconfirmed.forEach(username => {
            html += '<li><a href="#" data-check-in="' + escapeHtml(username) + '">' +
                escapeHtml(username) + '</a></li>';
        });
        html += '</ul></div></div>';
        return html;
    }

    _student_view() {
        const my_entry = this.get('my_entry');
        let html = this._banners();
        if (my_entry) {
            if (my_entry.data.claimant) {
                html += '<p><strong>You have been claimed by ' +
                    escapeHtml(my_entry.data.claimant_real_name ||
                               my_entry.data.claimant) + '</strong></p>' +
                    '<p>A staff member will be with you shortly.</p>';
            }
            else {
                const assignment = my_entry.data.assignment || {};
                html += '<p>You are in the queue at position <strong>' +
                    this.get('position') + '</strong> for ' +
                    escapeHtml(my_entry.type) +
                    (assignment.display_name
                     ? ' (' + escapeHtml(assignment.display_name) + ')' : '') + '</p>';
            }
            html += '<button class="queue-btn queue-btn-danger" data-remove>Remove</button>';
        }
        else {
            html += '<form class="queue-form" data-ask>' +
                '<label for="queue_location">Location</label>' +
                '<input type="text" id="queue_location" autocomplete="off" placeholder="e.g. table 6" value="' +
                escapeHtml(this.get('location')) + '">' +
                '<label for="queue_assignment">Assignment</label>' +
                '<input type="text" id="queue_assignment" autocomplete="off" placeholder="e.g. Check Yourself 2" value="' +
                escapeHtml(this.get('name')) + '">' +
                '<button type="submit" class="queue-btn queue-btn-primary"' +
                (this.get('name') ? '' : ' disabled') + '>Ask for Help</button></form>';
        }
        html += '<div class="queue-controls">' + this._notify_buttons() + '</div>';
        html += this._audio();
        return html;
    }

    _student_static() {
        let html = this._student_view();
        if (this.options.is_staff) {
            html += '<div><a href="?queue_view=staff">Switch to staff view</a></div>';
        }
        return html;
    }

    _student_popup() {
        let html = '<div id="queue_div">';
        if (this.get('_visible')) html += this._student_view();
        html += '<div><button class="queue-btn" data-toggle-visible>' +
            (this.get('_visible') ? 'Hide' : 'Show') + ' Queue Controls' +
            '</button></div></div>';
        return html;
    }

    _notify_buttons() {
        let html = '';
        if (this.options.AUDIO_ENABLED) {
            html += '<button class="queue-btn" data-toggle-setting="notify_sound">' +
                (this.get('notify_sound') ? 'Disable' : 'Enable') + ' Sounds</button>';
        }
        html += '<button class="queue-btn" data-toggle-setting="notify_toast">' +
            (this.get('notify_toast') ? 'Disable' : 'Enable') + ' Popups</button>';
        return html;
    }

    _audio() {
        if (!this.options.AUDIO_ENABLED) return '';
        const url = this.options.get_audio_url;
        return '<audio id="queue-notification-sound">' +
            '<source src="' + escapeHtml(url('beep.wav')) + '" type="audio/wav">' +
            '<source src="' + escapeHtml(url('beep.ogg')) + '" type="audio/ogg">' +
            '<source src="' + escapeHtml(url('beep.mp3')) + '" type="audio/mp3">' +
            '</audio>';
    }

    /// Per-second time refresh (only touches the time nodes)

    _tick() {
        this.container.querySelectorAll('.queue-time').forEach(el => {
            el.textContent = timeAgo(el.getAttribute('data-since'));
        });
        this.container.querySelectorAll('[data-claim-since]').forEach(el => {
            el.textContent = claimTimer(el.getAttribute('data-claim-since'));
        });
    }

    /// UI events (delegated, so they survive re-renders)

    _wire_events() {
        this.container.addEventListener('click', event => {
            const target = event.target.closest('[data-act], [data-claim-first], ' +
                '[data-toggle-setting], [data-clear], [data-lock], [data-unlock], ' +
                '[data-remove], [data-toggle-visible], [data-check-in], ' +
                '[data-check-out], [data-check-out-all]');
            if (!target || !this.container.contains(target)) return;

            if (target.hasAttribute('data-act')) {
                target.disabled = true;
                this.client.action(target.getAttribute('data-act'), {
                    username: target.getAttribute('data-entry'),
                }).then(() => { target.disabled = false; });
            }
            else if (target.hasAttribute('data-claim-first')) {
                const first = this.get('first_unclaimed');
                if (first) {
                    target.disabled = true;
                    this.client.action('claim', {username: first.username})
                        .then(() => { target.disabled = false; });
                }
            }
            else if (target.hasAttribute('data-toggle-setting')) {
                this.queue.toggle_setting(target.getAttribute('data-toggle-setting'));
            }
            else if (target.hasAttribute('data-clear')) this.queue.clear_with_confirm();
            else if (target.hasAttribute('data-lock')) this.queue.lock_with_confirm();
            else if (target.hasAttribute('data-unlock')) this.client.unlock();
            else if (target.hasAttribute('data-remove')) this.queue.remove();
            else if (target.hasAttribute('data-toggle-visible')) this.toggle('_visible');
            else if (target.hasAttribute('data-check-in')) {
                event.preventDefault();
                this.client.check_in(target.getAttribute('data-check-in'));
            }
            else if (target.hasAttribute('data-check-out')) {
                event.preventDefault();
                this.client.check_out(target.getAttribute('data-check-out'));
            }
            else if (target.hasAttribute('data-check-out-all')) {
                event.preventDefault();
                (this.get('confirmed_staff') || [])
                    .forEach(username => this.client.check_out(username));
            }
        });

        // Keep the ask-for-help form fields in the model across re-renders.
        this.container.addEventListener('input', event => {
            if (event.target.id === 'queue_location') {
                this.set_silent('location', event.target.value);
            }
            if (event.target.id === 'queue_assignment') {
                this.set_silent('name', event.target.value);
                // enable/disable the submit button without a full render
                const button = event.target.closest('form')
                    .querySelector('button[type=submit]');
                if (button) button.disabled = !event.target.value;
            }
        });

        this.container.addEventListener('submit', event => {
            if (event.target.hasAttribute('data-ask')) {
                event.preventDefault();
                this.queue.askForHelp();
            }
        });

        // Keyboard shortcuts (Mousetrap replacement).
        document.addEventListener('keydown', event => {
            if (this.options.view !== 'staff_view') return;
            if (/INPUT|TEXTAREA|SELECT/.test(document.activeElement.tagName)) return;
            if (event.ctrlKey || event.metaKey || event.altKey) return;

            if (this.get('current_claim')) {
                const button = this.container.querySelector(
                    '.action-button[data-shortcut="' + event.key + '"]');
                if (button) button.click();
            }
            else if (event.key === 'c') {
                const button = this.container.querySelector('[data-claim-first]');
                if (button && !button.disabled) button.click();
            }
        });
    }

    // Ractive-style access to the beep element
    get nodes() {
        return {
            'queue-notification-sound':
                document.getElementById('queue-notification-sound'),
        };
    }
}

/// The queue app (port of the original www/js/queue.js Queue class)

class Queue {
    constructor(options) {
        this.options = options;
        this.client = new QueueClient({
            socket_url: options.socket_url || ws_url(options.url_root),
            room: options.room || 'default',
        });

        const url_root = options.url_root || '/';
        if (options.get_audio_url === undefined) {
            options.get_audio_url =
                filename => url_join(url_root, 'audio', filename);
        }
        options.AUDIO_ENABLED = Boolean(options.get_audio_url);
        options.PHOTOS_ENABLED = Boolean(options.get_photo_url);

        this.view = new View(this.client, options);
        this.view.queue = this;

        this.get = this.view.get.bind(this.view);
        this.set = this.view.set.bind(this.view);
        this.observe = this.view.observe.bind(this.view);

        this.client.recv('connect', () => this.set('disconnected', false));
        this.client.recv('disconnect', () =>
            setTimeout(() => this.set('disconnected', true), 1e3));

        if (options.view === 'staff_view') {
            this.observe('fraction_unclaimed', (fraction) => {
                const parts = fraction || [0, 0];
                document.title = '(' + parts[0] + '/' + parts[1] + ') Queue';
            });
        }

        this.client.recv('edit', (msg) => {
            if (msg.added_entries.length && options.view === 'staff_view') {
                this.notify(msg.added_entries);
            }

            const prev_position = this.get('position');

            const dirty = msg.edited_entries.map(e => e.username)
                .concat(msg.deleted_usernames);
            const entries = (this.get('entries') || [])
                .filter(e => !dirty.includes(e.username))
                .concat(msg.edited_entries)
                .concat(msg.added_entries);
            entries.sort(queue_sort_order);
            this.set('entries', entries);

            const mine = this.get('my_entry');
            if (mine && mine.data.claimant && prev_position > 0) {
                this.notify_student((mine.data.claimant_real_name ||
                                     mine.data.claimant) + ' is ready to help!');
            }
        });

        this.client.recv('locked', locked => this.set('locked', locked));

        this.client.recv('staff_list', (msg) => {
            const removed = new Set(msg.removed);
            const checked_in = new Set(msg.checked_in);
            const confirmed = new Set(this.get('confirmed_staff'));
            const unconfirmed = new Set(this.get('unconfirmed_staff'));
            removed.forEach(u => { confirmed.delete(u); unconfirmed.delete(u); });
            checked_in.forEach(u => { confirmed.add(u); unconfirmed.delete(u); });
            msg.logged_in.forEach(u => { if (!confirmed.has(u)) unconfirmed.add(u); });
            this.set('confirmed_staff', Array.from(confirmed).sort());
            this.set('unconfirmed_staff', Array.from(unconfirmed).sort());
        });
    }

    login(callback) {
        let auth_msg;
        if (typeof this.options.auth === 'string') {
            // Current CAT-SOOP: catsoop.plugins.queue.auth is the signed
            // cs_user_info blob from the plugin's post_load.py; pass it
            // through for the queue server to verify.
            auth_msg = {auth: this.options.auth};
        }
        else {
            // Older CAT-SOOP (catsoop.api_token) or a dev-mode
            // {username, role} object (see test_queue.html).
            auth_msg = Object.assign(
                {
                    api_token: window.catsoop ? catsoop.api_token : null,
                    course: window.catsoop ? catsoop.course : null,
                },
                this.options.auth || {}
            );
        }
        this.client.login(auth_msg, auth => {
            if (auth && !auth.error) {
                this.setup(auth.permissions);
            }
            else {
                console.error('queue: login failed:',
                              auth ? auth.error : 'no response from server',
                              '(auth type: ' +
                              (typeof this.options.auth === 'string'
                               ? 'signed blob' : 'api_token/dev') + ')');
            }
            if (callback) callback(auth);
        });
    }

    setup(permissions) {
        this.client.is_locked().then(locked => this.set('locked', locked));

        this.client.get_entries().then(entries => {
            entries.sort(queue_sort_order);
            this.set('entries', entries);
        });

        this.client.get_staff_list().then(staff => {
            this.set('confirmed_staff', Array.from(staff.confirmed));
            this.set('unconfirmed_staff', Array.from(staff.unconfirmed));
        });

        const perms = {};
        permissions.forEach(p => { perms[p] = true; });
        this.set('permissions', perms);

        ['notify_sound', 'notify_toast', 'show_claimed'].forEach(setting => {
            const stored = JSON.parse(localStorage.getItem(setting));
            this.set(setting, stored === null ? true : stored);
        });
    }

    askForHelp() {
        this.add('help', {
            location: this.get('location'),
            assignment: {
                display_name: this.get('name'),
                name: this.get('name'),
                page: this.options.page,
                path: this.options.path,
            },
        });
    }

    add(type, data) {
        this.client.add(type, data).then(result => {
            if (!result.success) {
                modal('The queue is locked',
                      'The queue is not accepting new entries at this time.',
                      false, false);
            }
        });
    }

    remove() {
        if (this.get('my_entry')) this.client.remove();
    }

    lock() { return this.client.lock(); }
    unlock() { return this.client.unlock(); }
    clear() { return this.client.clear(); }

    lock_with_confirm() {
        modal('Are you sure you want to lock the queue?',
              'This will prevent anyone from adding themselves to the queue.',
              false, true)
            .then(res => { if (res) this.client.lock(); });
    }

    clear_with_confirm() {
        modal('Are you sure you want to clear the queue?',
              'This will remove everyone from the queue.',
              false, true)
            .then(res => { if (res) this.client.clear(); });
    }

    toggle_setting(setting) {
        this.view.toggle(setting).then(() => {
            const value = this.get(setting);
            localStorage.setItem(setting, value);
            if (setting === 'notify_sound' && value) this._beep();
            if (setting === 'notify_toast' && value && window.Notification) {
                Notification.requestPermission(() => {});
            }
        });
    }

    _beep() {
        const beep = this.view.nodes['queue-notification-sound'];
        if (beep) beep.play().catch(() => {});
    }

    _toast(title, body) {
        if (!window.Notification) return;
        if (Notification.permission === 'granted') {
            new Notification(title, {body});
        }
        else {
            Notification.requestPermission(permission => {
                if (permission === 'granted') new Notification(title, {body});
            });
        }
    }

    notify(new_entries) {
        if (this.get('notify_sound')) this._beep();
        if (this.get('notify_toast')) {
            this._toast("There's a queue!", new_entries.map(entry =>
                entry.username + ' @ ' + (entry.data.location || '?') + ' : ' +
                ((entry.data.assignment || {}).display_name || '')
            ).join('\n'));
        }
    }

    notify_student(message) {
        if (this.get('notify_sound')) this._beep();
        if (this.get('notify_toast')) this._toast('Queue alert', message);
    }
}

/// Bootstrapping (port of the original $(() => {...}))

function ensure_client(url_root, callback) {
    if (window.QueueClient) return callback();
    const script = document.createElement('script');
    script.src = url_join(url_root || '/', 'js', 'client.js');
    script.onload = callback;
    document.head.appendChild(script);
}

function boot() {
    const config = window.catsoop && catsoop.plugins && catsoop.plugins.queue;
    if (!config) {
        console.log('queue has no catsoop.plugins.queue config ... exiting');
        return;
    }
    if (config.auth == null && catsoop.api_token == null) {
        console.log('queue has no auth credential ' +
                    '(catsoop.plugins.queue.auth or catsoop.api_token) ... exiting');
        return;
    }

    const options = Object.assign({},
        config,
        {page: catsoop.this_path, path: catsoop.path_info},
        window.queue_www_params || {});

    ensure_client(options.url_root, () => {
        window.queue = new Queue(options);

        window.queue.observe('my_entry', function (cur, old) {
            if (!old && cur) this.set('_visible', true);

            // When a checkoff entry disappears with a passing score,
            // re-render that question's div on the CAT-SOOP page.
            if (old && !cur && catsoop.this_page && old.data.assignment) {
                const name = old.data.assignment.name;
                const form = (extra) => {
                    const body = new URLSearchParams(Object.assign(
                        catsoop.api_token != null
                            ? {api_token: catsoop.api_token} : {},
                        extra));
                    return {method: 'POST', body,
                            headers: {'Content-Type':
                                      'application/x-www-form-urlencoded'}};
                };
		console.log(`fetching {form} from {catsoop.this_page}`);
                fetch(catsoop.this_page, form({action: 'get_state'}))
                    .then(res => res.json())
                    .then(({scores}) => {
                        if (!scores || scores[name] !== 1) return;
                        fetch(catsoop.this_page,
                              form({action: 'render_single_question', name}))
                            .then(res => res.text())
                            .then(html => {
                                const qdiv = document.getElementById('cs_qdiv_' + name);
                                if (qdiv) qdiv.innerHTML = html;
                            });
                    })
                    .catch(() => {});
            }
        });

        window.queue.login();
    });
}

window.QueueApp = Queue;
if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', boot);
}
else {
    boot();
}

})();
